class Solution {
public:
    string solve(TreeNode* root) {
        string result = '';
        void dfs(TreeNode* node) {
            if (!node) return;
            result += to_string(node->val);
            dfs(node->left);
            dfs(node->right);
        }
        dfs(root);
        // replace space with '-'
        string res = result;
        for (int i = 0; i < res.length(); i++) {
            if (res[i] == ' ') res[i] = '-';
        }
        return res;
    }
};

// Read input
#include <iostream>
#include <cstdio>

using namespace std;

void read_input(TreeNode*& root) {
    int n;
    cin >> n;
    root = new TreeNode(1);
    queue<TreeNode*> q;
    q.push(root);
    int i = 2;
    while (i <= n) {
        int val;
        cin >> val;
        if (!q.empty()) {
            TreeNode* node = q.front(); q.pop();
            if (i <= n) {
                node->left = new TreeNode(val);
                q.push(node->left);
                i++;
            }
            if (i <= n) {
                node->right = new TreeNode(0);
                q.push(node->right);
                i++;
            }
        }
    }
}

// Driver code
int main() {
    TreeNode* root;
    read_input(root);
    Solution sol;
    cout << sol.solve(root) << endl;
    return 0;
}
